import React, { useCallback, useMemo, useState } from 'react';
import {
  Button,
  Input,
  SearchTextInput,
  Modal, dispatchAppToast,
  LeaveConfirmModal,
  LinListFilterField,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import { exportUnitsCsv } from '../../../services/master/catalogExport';
import type { UnitDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { useCatalogListSelection } from '../../../hooks/useCatalogListSelection';
import { useCatalogMasterListRowMenu } from '../../../hooks/useCatalogMasterListRowMenu';
import {
  CatalogFormFooter,
  useCatalogListPaging,
  useServerPagedListLoading,
  SharedCatalogFormActions,
  useSharedCatalog,
  sharedCatalogFormProps,
  isSharedCatalogReadOnly,
  CatalogDocumentHistory,
  CatalogFormHistorySlot,
  CatalogFormCodeReplaceSlot,
  CatalogCodeReplaceProvider,
  CatalogLegacyCodeSuffix,
  CatalogListExportButton,
  CatalogListHeaderFilters,
  CatalogListMasterLinPageLayout,
  CatalogRowActionMenu,
} from '../../../components/catalog';
import {
  CatalogListGridFromSchema,
  CatalogUiSchemaEditorModal,
  useCatalogUiSchema,
  listVisibleFields,
  proposalEditableFields,
  toProposalFieldDefs,
} from '../../../components/catalog/catalogUiSchema';
import type { CatalogBatchDeleteMode } from '../../../components/catalog';
import { masterCatalogDocumentTypes } from '../../../config/documentHistoryClients';
import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-don-vi-tinh';
const CATALOG_KIND = 'units';

type FormErrors = Partial<Record<'code' | 'name', string>>;

const DonViTinhPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<UnitDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<UnitDto | null>(null);
  const [form, setForm] = useState<Partial<UnitDto>>({ isActive: true });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [viewOnlyShared, setViewOnlyShared] = useState(false);
  const [schemaEditorOpen, setSchemaEditorOpen] = useState(false);

  const { schema, reload: reloadSchema } = useCatalogUiSchema(CATALOG_KIND);
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const proposalFieldDefs = useMemo(
    () => toProposalFieldDefs(proposalEditableFields(schema)),
    [schema],
  );

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const {
    showTableLoading,
    pageLoading,
    pulseSearch,
    setLoadingMode,
    beginFetch,
    endFetch,
  } = useServerPagedListLoading();

  const selection = useCatalogListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable: () => true,
  });

  const refresh = () => {
    setLoadingMode('filter');
    selection.clearSelection();
    setReloadKey(k => k + 1);
  };
  const shared = useSharedCatalog(CATALOG_KIND, refresh);
  const sharedForm = sharedCatalogFormProps(CATALOG_KIND, shared);

  const handleSearch = () => {
    pulseSearch(() => {
      setLoadingMode('filter');
      setSearch(searchDraft.trim());
      resetPage();
      selection.clearSelection();
    });
  };

  React.useEffect(() => {
    let cancelled = false;
    beginFetch();
    const t = setTimeout(() => {
      masterService
        .getUnits({ search: search.trim() || undefined, page, pageSize })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: err instanceof Error ? err.message : 'Lỗi tải đơn vị tính',
              type: 'error',
            });
          }
        })
        .finally(() => { if (!cancelled) endFetch(); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, page, pageSize, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!editing && !form.code?.trim()) next.code = 'Nhập mã đơn vị tính';
    if (!form.name?.trim()) next.name = 'Nhập tên đơn vị tính';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = () => {
    setViewOnlyShared(false);
    setEditing(null);
    setForm({ isActive: true });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openView = useCallback((row: UnitDto) => {
    setViewOnlyShared(true);
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
    void masterService.getUnit(row.id).then(full => {
      setEditing(full);
      setForm({ ...full });
    }).catch(() => { /* list row sufficient */ });
  }, [markClean]);

  const openEditImpl = useCallback((row: UnitDto) => {
    setViewOnlyShared(false);
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
    void masterService.getUnit(row.id).then(full => {
      setEditing(full);
      setForm({ ...full });
    }).catch(() => { /* list row sufficient */ });
  }, [markClean]);

  const rowMenu = useCatalogMasterListRowMenu({
    testIdPrefix: TEST_ID,
    catalogKind: CATALOG_KIND,
    selection,
    openEdit: openEditImpl,
    openView,
  });

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) {
        await masterService.updateUnit(editing.id, {
          name: form.name!.trim(),
          isActive: form.isActive ?? true,
        });
      } else {
        await masterService.createUnit({
          code: normalizeCode(form.code!),
          name: form.name!.trim(),
        });
      }
      markClean();
      dispatchAppToast(dispatch, {
        message: editing ? 'Cập nhật đơn vị tính thành công' : 'Tạo đơn vị tính thành công',
        type: 'success',
      });
      setModalOpen(false);
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleBatchDelete = async (mode: CatalogBatchDeleteMode) => {
    const ids =
      selection.selectionMode === 'all'
        ? items.filter(r => !isSharedCatalogReadOnly(r)).map(r => r.id)
        : [...selection.selectedIds].filter(id => {
            const row = items.find(r => r.id === id);
            return row && !isSharedCatalogReadOnly(row);
          });
    if (ids.length === 0) throw new Error('Không có bản ghi hợp lệ để xóa');
    if (mode === 'soft') {
      await Promise.all(ids.map(id => {
        const row = items.find(r => r.id === id)!;
        return masterService.updateUnit(id, {
          name: row.name,
          isActive: false,
        });
      }));
      dispatchAppToast(dispatch, { message: `Đã ngưng ${ids.length} đơn vị tính`, type: 'success' });
    } else {
      await Promise.all(ids.map(id => masterService.deleteUnit(id)));
      dispatchAppToast(dispatch, { message: `Đã xóa ${ids.length} đơn vị tính`, type: 'success' });
    }
    refresh();
  };

  return (
    <CatalogCodeReplaceProvider catalogKind={CATALOG_KIND}>
    <>
      <CatalogListMasterLinPageLayout
        testIdPrefix={TEST_ID}
        catalogKind={CATALOG_KIND}
        shared={shared}
        selection={selection}
        totalCount={totalCount}
        selectableOnPage={items.filter(r => !isSharedCatalogReadOnly(r))}
        onAdd={openAdd}
        onEdit={rowMenu.openEditWithPerm}
        onRefresh={refresh}
        toolbarExtraLeftActions={(
          <CatalogListExportButton
            testIdPrefix={TEST_ID}
            onExport={() => exportUnitsCsv({ search: search || undefined })}
          />
        )}
        onBatchDelete={handleBatchDelete}
        showSchemaConfig
        onOpenSchemaConfig={() => setSchemaEditorOpen(true)}
        proposalFieldDefs={proposalFieldDefs.length > 0 ? proposalFieldDefs : undefined}
        toolbarBridgeRef={rowMenu.toolbarBridgeRef}
        page={page}
        pageSize={pageSize}
        onPageChange={p => { setLoadingMode('page'); setPage(p); selection.clearSelection(); }}
        onPageSizeChange={size => { setLoadingMode('filter'); setPageSize(size); }}
        showTableLoading={showTableLoading}
        pageLoading={pageLoading}
        header={{
          title: 'Danh mục đơn vị tính',
          titleIconClass: 'fas fa-ruler',
        }}
        listTitle="Danh sách đơn vị tính"
        listRowMenuHelp
        filtersTestId={`${TEST_ID}-filters`}
        filterMaxWidthPx={1000}
        filters={(
          <CatalogListHeaderFilters testIdPrefix={TEST_ID} filterMaxWidthPx={1000}>
            <LinListFilterField testId={`${TEST_ID}-field-search`}>
              <SearchTextInput
                label="Tìm kiếm"
                placeholder="Tìm mã, tên..."
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleSearch}
                testId={`${TEST_ID}-search-text`}
              />
            </LinListFilterField>
          </CatalogListHeaderFilters>
        )}
        schemaEditorModal={(
          <CatalogUiSchemaEditorModal
            testIdPrefix={TEST_ID}
            catalogKind={CATALOG_KIND}
            isOpen={schemaEditorOpen}
            onClose={() => setSchemaEditorOpen(false)}
            onSaved={() => {
              reloadSchema();
              refresh();
            }}
          />
        )}
        extraModals={(
          <>
            <CatalogRowActionMenu {...rowMenu.rowActionMenuProps} />
            <LeaveConfirmModal {...leaveConfirmModalProps} />
          </>
        )}
      >
        {items.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy đơn vị tính phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : listColumns.length > 0 ? (
          <CatalogListGridFromSchema
            testIdPrefix={TEST_ID}
            rows={items}
            page={page}
            pageSize={pageSize}
            columns={listColumns}
            schema={schema}
            selection={selection}
            getRowId={r => r.id}
            isRowSelectable={r => !isSharedCatalogReadOnly(r)}
            {...rowMenu.gridRowMenuProps}
          />
        ) : null}
      </CatalogListMasterLinPageLayout>

      <Modal
        isOpen={modalOpen}
        onClose={closeFormModal}
        title={viewOnlyShared ? 'Xem đơn vị tính dùng chung' : editing ? 'Sửa đơn vị tính' : 'Thêm đơn vị tính'}
        size="md"
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã đơn vị tính *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing || viewOnlyShared}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
                <CatalogLegacyCodeSuffix
                  testIdPrefix={TEST_ID}
                  code={editing?.code}
                  legacyCode={editing?.legacyCode}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên đơn vị tính *</label>
                <Input
                  value={form.name ?? ''}
                  disabled={viewOnlyShared}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
          </div>
          <SharedCatalogFormActions
            testIdPrefix={TEST_ID}
            row={editing}
            currentValues={{ name: form.name, isActive: form.isActive }}
            {...sharedForm}
          />
          {viewOnlyShared ? (
            <div className={styles.modalActions}>
              <CatalogDocumentHistory
                testIdPrefix={TEST_ID}
                documentType={masterCatalogDocumentTypes.units}
                documentId={editing?.id}
                documentCode={editing?.code}
              />
              <Button variant="secondary" onClick={closeFormModal}>Đóng</Button>
            </div>
          ) : (
            <CatalogFormFooter
              companyName={editing?.companyName ?? sessionCompanyName}
              testIdPrefix={TEST_ID}
              checked={form.isActive ?? true}
              onActiveChange={c => {
                markDirty();
                setForm(f => ({ ...f, isActive: c }));
              }}
              onCancel={closeFormModal}
              onSave={handleSave}
              saving={saving}
              historySlot={
              <>
                <CatalogFormCodeReplaceSlot
                  testIdPrefix={TEST_ID}
                  catalogKind={CATALOG_KIND}
                  editing={editing ? { id: editing.id, code: editing.code } : null}
                  reloadKey={reloadKey}
                />
                <CatalogFormHistorySlot
                  testIdPrefix={TEST_ID}
                  catalogKind={CATALOG_KIND}
                  editing={editing ? { id: editing.id, code: editing.code } : null}
                />
              </>
              }
            />
          )}
        </div>
      </Modal>
    </>
      </CatalogCodeReplaceProvider>
  );
};

export default DonViTinhPage;
